#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e+5+5;
struct node{
	int c,p;
}h[MAXN],s[MAXN];
int q,n,m,t,o,x,c;
int main(void){
	cin>>t;
	while(t--){
		memset(h,0,sizeof(h));
		memset(s,0,sizeof(s));
		cin>>n>>m>>q;
		for(int i=1;i<=q;i++){
			cin>>o>>x>>c;
			if(o)s[x].c=c,s[x].p=i;
			else h[x].c=c,h[x].p=i;
		}for(int i=1;i<=n;i++){
			for(int j=1;j<=m;j++){
				cout<<((h[i].p>s[j].p)?(h[i].c):(s[j].c))<<' ';
			}cout<<"\n";
		}
	}
    return false;
}
